const rows = $input.all();
const config = {};
for (const r of rows) config[r.json.key] = r.json.value;
const direct = $('Unify Input').first().json.direct_company;
return [{ json: { config, direct_company: direct } }];

const q = $input.first().json;
const config = $('Build Config Map').first().json.config;
const company = q.company_name;
return [
  { json: { queue_id: q.id, company, country: q.country, tier: q.tier, config, query: `"${company}" supplier manufacturer` } },
  { json: { queue_id: q.id, company, country: q.country, tier: q.tier, config, query: `"${company}" supply chain sourcing` } },
  { json: { queue_id: q.id, company, country: q.country, tier: q.tier, config, query: `"${company}" annual report suppliers` } }
];

const results = $input.all();
const config = $('Build Config Map').first().json.config;
const queue_item = $('Claim Queue Item').first().json;
const max_results = parseInt(config.search_results_per_query || '3');

const urls = [];
for (const r of results) {
  const hits = r.json?.results || [];
  for (const hit of hits.slice(0, max_results)) {
    if (hit.url && !hit.url.includes('linkedin.com') && !hit.url.includes('facebook.com')) {
      urls.push({ url: hit.url, title: hit.title, snippet: hit.content || '' });
    }
  }
}

const unique_urls = urls.filter((v, i, a) => a.findIndex(u => u.url === v.url) === i).slice(0, 6);
return unique_urls.map(u => ({ json: { ...u, company: queue_item.company_name, queue_id: queue_item.id, tier: queue_item.tier } }));

// Use snippet from search result as page content
// Browserless is optional enrichment; snippets are sufficient for LLM extraction
const item = $input.first().json;
const body = item.snippet || item.title || '';
return [{ json: { body, url: item.url } }];

const page = $input.first().json;
const ctx = $('Collect Unique URLs').first().json;
const config = $('Build Config Map').first().json.config;
const max_claims = parseInt(config.max_claims_per_batch || '5');

let raw_text = '';
try {
  const body = page?.body || page?.data || '';
  if (typeof body === 'string' && body.length > 0) {
    raw_text = body.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  }
} catch(e) {}
if (!raw_text || raw_text.length < 50) raw_text = ctx.snippet || ctx.title || '';
raw_text = raw_text.substring(0, 3000);

const company = config.seed_company || ctx.company || 'Unknown';
const prompt = `Extract supply chain relationships involving "${company}" from the following web content.

Source URL: ${ctx.url}
Content: ${raw_text}

Return a JSON object with this EXACT structure (no markdown):
{"claims": [{"subject": "Company Name", "predicate": "SUPPLIES|BUYS_FROM|MANUFACTURES|DISTRIBUTES|PARTNERS_WITH|CERTIFIES|LOCATED_IN", "object": "Other Company or Product or Location", "confidence": 0.0-1.0, "source_url": "${ctx.url}"}]}

Rules:
- subject: the company/organization that is the source of the relationship
- predicate: one of the exact strings above
- object: the target company, product, material, or location
- confidence: how certain you are (0.5-1.0)
- Only include claims with confidence >= 0.5
- Max ${max_claims} claims
- If no supply chain relationships found, return: {"claims": []}`;

return [{ json: { prompt, company, url: ctx.url, config } }];

const resp = $input.first().json;
const ctx = $('Build Config Map').first().json;
const company = ctx.company;

let claims = [];
try {
  let content = resp?.choices?.[0]?.message?.content || '{}';
  // Strip markdown code blocks
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  const parsed = JSON.parse(content);
  // Handle both {"claims": [...]} and [...] formats
  if (Array.isArray(parsed)) {
    claims = parsed;
  } else if (parsed.claims && Array.isArray(parsed.claims)) {
    claims = parsed.claims;
  }
} catch(e) { claims = []; }

const confidence_threshold = parseFloat(ctx.config?.confidence_threshold || '0.5');

return claims
  .filter(c => c.subject && c.object && (c.confidence || 0) >= confidence_threshold)
  .map(c => ({
    json: {
      subject: c.subject || company,
      predicate: c.predicate || 'SUPPLIES',
      object: c.object,
      confidence: c.confidence || 0.7,
      source_url: c.source_url || resp?.choices?.[0]?.message?.content?.slice(0,50) || '',
      raw_text: '',
      tier: 1
    }
  }));
